%[text] ## Section 5: GNNの解釈
%[text] ### GNN は何を学習したか
%[text] 線形回帰（A03）とは異なり、GNN の重みは「特徴量重要度」として直接検査することができません。
%[text] GNN の解釈手法には主に 2 種類があります。
%[text] 一つ目は**勾配サリエンシー**（saliency: 際立ち度の意）で、各原子の $\\partial L / \\partial h(v, 0)$ を計算します。
%[text] 勾配ノルムが大きい原子が予測に最も大きな影響を与えます。
%[text] 実装では、原子特徴行列 $x$ に `requires_grad=True` を設定してフォワードパスを実行し、`loss.backward()` で勾配を計算して `x.grad` を読み取ります。
%[text] 二つ目は**グラフアテンションネットワーク**（GAT: Graph Attention Network、Velickovic et al. 2018）で、GCNConv を GATConv に置き換えます。
%[text] 各アテンションヘッドはエッジ $(u, v)$ の重要度を表すアテンション係数 $\\alpha(u, v) \\in \[0, 1\]$ を学習し、可視化することで結合ごとの帰属が得られます。
%[text] 本演習では完全な勾配サリエンシーの代わりに、MATLAB 側で `emk.descriptor` API を使った簡略化プロキシ（物性寄与の可視化）を示します。
%[text] デモ分子としてアスピリンを使います。
DEMO_SMILES2 = "CC(=O)Oc1ccccc1C(=O)O";  % aspirin  (same as Section 2)
mol_asp   = emk.mol.fromSmiles(DEMO_SMILES2);
descNames = ["MolWt", "TPSA", "NumHDonors", "NumHAcceptors", ...
             "NumRotatableBonds", "RingCount", "FractionCSP3"];
desc_asp  = emk.descriptor.calculate(mol_asp, descNames);
logInfo("R09 アスピリン記述子（サリエンシープロキシ用）:"); %[output:79b1df11]
for di = 1:numel(descNames) %[output:group:5f20b6c2]
    logInfo("  %s = %.3f", descNames(di), desc_asp.(descNames(di))); %[output:51d67b20]
end %[output:group:5f20b6c2]
%[text] 正規化された記述子値をサリエンシーのプロキシとして棒グラフに示します。
descVals    = zeros(1, numel(descNames));
for di = 1:numel(descNames)
    descVals(di) = desc_asp.(descNames(di));
end
descValsNorm = abs(descVals - mean(descVals)) / (std(descVals) + 1e-8);
figure("Name", "R09 Descriptor Contribution (Saliency Proxy)"); %[output:07ba899d]
barh(descValsNorm, FaceColor=[0.2 0.6 0.4]); %[output:07ba899d]
yticks(1:numel(descNames)); yticklabels(descNames); %[output:07ba899d]
xlabel("平均からの正規化偏差"); %[output:07ba899d]
title(sprintf("%s の記述子寄与（サリエンシープロキシ）", DEMO_NAME)); %[output:07ba899d]
grid on; %[output:07ba899d]
%[text] 最終サマリー
logInfo(string(repmat('=', 1, 60))); %[output:6c06246a]
logInfo("R09 サマリー"); %[output:91c29be4]
logInfo("  GCN テストRMSE  = %.3f ALogP単位", gcn_rmse_test); %[output:90733113]
logInfo("  GCN テストMAE   = %.3f ALogP単位", gcn_mae_test); %[output:8106f343]
logInfo("  GCN テストR2    = %.3f", gcn_r2_test); %[output:1bbb95bf]
logInfo("  モデルパラメータ数 = %d", gnnRes.num_params); %[output:6140983a]
logInfo("  原子特徴量     = %d 次元", gnnRes.num_atom_features); %[output:73763f3a]
logInfo("  学習           = %d エポック x %d 分子（%d グラフ/バッチ）", ... %[output:group:66c0d21e] %[output:7821e0bf]
    gnnRes.num_epochs, gnnRes.num_train, GNN_BATCH); %[output:group:66c0d21e] %[output:7821e0bf]
logInfo("  結果保存先    : %s", outputJsonPath); %[output:19da8d65]
